Spring Boot Application:
```java
@SpringBootApplication
public class SpringBootApp {

    public static void main(String[] args) {
        SpringApplication.run(SpringBootApp.class, args);
    }

    @PostMapping("/python-service")
    public ResponseEntity<String> pythonService(@RequestBody String requestData) throws IOException, InterruptedException {
        // Write request data to file
        Path requestFilePath = Files.createTempFile("request-", ".txt");
        Files.write(requestFilePath, requestData.getBytes());

        // Call Python script with file path as argument
        String os = System.getProperty("os.name").toLowerCase();
        String pythonCommand = null;
        if (os.contains("windows")) {
            pythonCommand = "python";
        } else if (os.contains("linux") || os.contains("mac")) {
            pythonCommand = "python3";
        }
        ProcessBuilder pb = new ProcessBuilder(pythonCommand, "path/to/python/script.py", requestFilePath.toString());
        pb.redirectErrorStream(true);
        Process process = pb.start();
        process.waitFor();

        // Read response data from file
        Path responseFilePath = Paths.get(requestFilePath.toString() + ".response");
        String responseData = Files.readString(responseFilePath);
        Files.delete(requestFilePath);
        Files.delete(responseFilePath);

        // Return response
        return ResponseEntity.ok(responseData);
    }
}
```
