        $count = 1;
        while ($i + $count < strlen($data) && $data[$i] == $data[$i + $count]) {
            $count++;
        }
        if ($count > 1) {
            $compressed .= $count . $data[$i];
        } else {
            $compressed .= $data[$i];
        }
        $i += $count;
    }
    return $compressed;
}

